package config

import (
	"encoding/json"
	"fmt"
	"os"
	"path/filepath"
)

// ConfigFileName is the per-stack config file name.
const ConfigFileName = "config.json"

// CloudInitFileName is the per-stack cloud-init template file name.
const CloudInitFileName = "cloud-init.yaml"

// StackDir returns the directory for a named stack under the base folder.
