		{"apex no domain", &Config{VM: &VMConfig{Name: "web", Users: []User{{Username: "ubuntu", GitHubUsername: "alice"}}}, DNS: &DNSConfig{IsApexDomain: true}}, true},
		{"cname with domain", &Config{VM: &VMConfig{Name: "web", Users: []User{{Username: "ubuntu", GitHubUsername: "alice"}}}, DNS: &DNSConfig{Domain: "example.com", CNAMEAliases: []string{"www"}}}, false},
	}
