package libvirt

import (
	"context"
	"fmt"
	"os"
	"path/filepath"
)

// metaData returns the NoCloud meta-data document for a VM.
func metaData(name string) string {
	return fmt.Sprintf("instance-id: govirt-%s\nlocal-hostname: %s\n", name, name)
}

// isoTool identifies the available NoCloud ISO generator.
type isoTool int

const (
	isoNone isoTool = iota
	isoCloudLocalds
	isoGenisoimage
)

// buildISO writes the processed user-data and generated meta-data to a temp
// staging dir and produces a NoCloud datasource ISO at outputPath using the
// selected tool.
func buildISO(ctx context.Context, r Runner, tool isoTool, name, userData, outputPath string) error {
	stage, err := os.MkdirTemp("", "govirt-cidata-")
	if err != nil {
		return fmt.Errorf("creating ISO staging dir: %w", err)
	}
	defer os.RemoveAll(stage)

	userDataPath := filepath.Join(stage, "user-data")
	metaDataPath := filepath.Join(stage, "meta-data")
	if err := os.WriteFile(userDataPath, []byte(userData), 0o644); err != nil {
		return fmt.Errorf("writing user-data: %w", err)
	}
	if err := os.WriteFile(metaDataPath, []byte(metaData(name)), 0o644); err != nil {
		return fmt.Errorf("writing meta-data: %w", err)
	}

	switch tool {
	case isoCloudLocalds:
		return r.Run(ctx, "cloud-localds", outputPath, userDataPath, metaDataPath)
	case isoGenisoimage:
		return r.Run(ctx, "genisoimage",
			"-output", outputPath,
			"-volid", "cidata", "-joliet", "-rock",
			userDataPath, metaDataPath)
	default:
		return fmt.Errorf("neither cloud-localds nor genisoimage found: install cloud-image-utils or genisoimage")
	}
}

