// Package libvirt implements the local VM provider backed by libvirt/KVM. All
// hypervisor interaction shells out to virsh, virt-install, and qemu-img via an
// explicit-argument Runner (no shell), so VM names and paths cannot inject
// commands.
package libvirt

import (
	"context"
	"fmt"
	"io"
	"os"
	"os/exec"
	"path/filepath"
	"strconv"
	"strings"
	"syscall"
	"time"

	"github.com/gherlein/govirt/internal/cloudinit"
	"github.com/gherlein/govirt/internal/config"
	"github.com/gherlein/govirt/internal/provider"
)

// DefaultPoolDir is the libvirt default storage pool directory.
const DefaultPoolDir = "/var/lib/libvirt/images"

// DefaultNetwork is the libvirt network VMs attach to.
const DefaultNetwork = "default"

// ImageEnsurer resolves an image shorthand to a local cached base image path.
// *images.Manager satisfies it.
type ImageEnsurer interface {
	Ensure(ctx context.Context, image string) (string, error)
}

// Provider is the libvirt VMProvider implementation.
type Provider struct {
	Runner  Runner
	Images  ImageEnsurer
	PoolDir string
	Verbose bool
	Out     io.Writer
}

// New returns a Provider with production defaults.
func New(images ImageEnsurer) *Provider {
	return &Provider{
		Runner:  execRunner{},
		Images:  images,
		PoolDir: DefaultPoolDir,
		Out:     os.Stderr,
	}
}

// Name implements provider.VMProvider.
func (p *Provider) Name() string { return "local" }

func (p *Provider) out() io.Writer {
	if p.Out != nil {
