package main

import (
	"fmt"
	"os"
	"path/filepath"
	"strings"

	"github.com/gherlein/govirt/internal/config"
)

// parsedArgs is the result of parsing the command line.
type parsedArgs struct {
	command    string // create|destroy|list|ssh|status|stop|start|dns
	subcommand string // e.g. "swap" for "dns swap"
	name       string
	provider   string // "aws"|"do"|"local"|"" (auto-detect)
	dir        string
	folder     string
	users      string
	noHosts    bool
	verbose    bool
	version    bool
	help       bool
}

// parseArgs parses argv (excluding the program name). Flags may appear in any
// order and may be interspersed with positional arguments.
func parseArgs(argv []string) (parsedArgs, error) {
	var a parsedArgs
	var positionals []string

	for i := 0; i < len(argv); i++ {
		arg := argv[i]
		switch arg {
		case "--aws":
			a.provider = "aws"
		case "--do", "--digitalocean":
			a.provider = "do"
		case "--local":
			a.provider = "local"
		case "--no-hosts":
			a.noHosts = true
		case "--verbose", "-v":
			a.verbose = true
		case "--version":
			a.version = true
		case "--help", "-h":
			a.help = true
		case "--dir":
			val, err := nextValue(argv, &i, arg)
			if err != nil {
				return a, err
			}
			a.dir = val
		case "--folder", "-f":
			val, err := nextValue(argv, &i, arg)
			if err != nil {
				return a, err
			}
			a.folder = val
		case "--users", "-u":
			val, err := nextValue(argv, &i, arg)
			if err != nil {
				return a, err
			}
			a.users = val
		default:
			if strings.HasPrefix(arg, "-") {
				return a, fmt.Errorf("unknown flag: %s", arg)
			}
			positionals = append(positionals, arg)
		}
	}

	if len(positionals) > 0 {
		a.command = positionals[0]
	}
	if a.command == "dns" {
		if len(positionals) > 1 {
			a.subcommand = positionals[1]
		}
		if len(positionals) > 2 {
			a.name = positionals[2]
		}
	} else if len(positionals) > 1 {
		a.name = positionals[1]
	}
	return a, nil
}

// nextValue consumes the value following a flag that requires one.
func nextValue(argv []string, i *int, flag string) (string, error) {
	if *i+1 >= len(argv) {
		return "", fmt.Errorf("flag %s requires a value", flag)
	}
	*i++
	return argv[*i], nil
}

// resolveStackFolder applies the documented precedence:
// --folder > --dir/stacks > GOVIRT_STACK_FOLDER > ~/.config/govirt/stacks.
func resolveStackFolder(folder, dir, envFolder, home string) string {
	if folder != "" {
		return folder
	}
	if dir != "" {
		return filepath.Join(dir, "stacks")
	}
	if envFolder != "" {
		return envFolder
	}
	return filepath.Join(home, ".config", "govirt", "stacks")
}

// selectProvider returns the provider name from an explicit flag, or applies
// auto-detection from existing state sections.
func selectProvider(flag string, cfg *config.Config) string {
	if flag != "" {
		return flag
	}
	if cfg.DO != nil && cfg.Local == nil {
		return "do"
	}
	if cfg.AWS != nil && cfg.Local == nil {
		return "aws"
	}
	return "local"
}

// parseUsersOverride maps a comma-separated GitHub username list to VM users.
// The first username becomes the "ubuntu" account; the rest map username ==
// github_username.
func parseUsersOverride(spec string) []config.User {
	parts := strings.Split(spec, ",")
	var users []config.User
	for i, p := range parts {
		name := strings.TrimSpace(p)
		if name == "" {
			continue
		}
		if i == 0 {
			users = append(users, config.User{Username: "ubuntu", GitHubUsername: name})
		} else {
			users = append(users, config.User{Username: name, GitHubUsername: name})
		}
	}
	return users
}

// homeDir returns the user's home directory, falling back to "" on error.
func homeDir() string {
	h, err := os.UserHomeDir()
	if err != nil {
		return ""
	}
	return h
}

