package main

import (
	"bytes"
	"fmt"
	"os"
	"os/exec"
	"strings"
)

const hostsFile = "/etc/hosts"

// hostsBlock renders the marker-delimited /etc/hosts entry for a VM. fqdn may be
// empty, in which case only the VM name is listed.
func hostsBlock(name, ip, fqdn string) string {
	line := fmt.Sprintf("%s\t%s", ip, name)
	if fqdn != "" {
		line += " " + fqdn
	}
	return fmt.Sprintf("# govirt:%s\n%s\n# /govirt:%s\n", name, line, name)
}

// removeHostsBlock returns existing with any govirt block for name removed.
func removeHostsBlock(existing, name string) string {
	start := "# govirt:" + name
	end := "# /govirt:" + name
	lines := strings.Split(existing, "\n")
	var out []string
	skipping := false
	for _, line := range lines {
		trimmed := strings.TrimSpace(line)
		if trimmed == start {
			skipping = true
			continue
		}
		if skipping {
			if trimmed == end {
				skipping = false
			}
			continue
		}
		out = append(out, line)
	}
	return strings.Join(out, "\n")
}

// upsertHostsBlock removes any existing block for name and appends the new one.
func upsertHostsBlock(existing, name, block string) string {
	cleaned := strings.TrimRight(removeHostsBlock(existing, name), "\n")
	if cleaned == "" {
		return block
	}
	return cleaned + "\n" + block
}

// writeHostsFile writes content to /etc/hosts via `sudo tee`, piping content on
// stdin so nothing is interpolated into a shell command.
func writeHostsFile(content string) error {
	cmd := exec.Command("sudo", "tee", hostsFile)
	cmd.Stdin = bytes.NewReader([]byte(content))
	cmd.Stdout = nil
	var stderr bytes.Buffer
	cmd.Stderr = &stderr
	if err := cmd.Run(); err != nil {
		return fmt.Errorf("updating %s: %s: %w", hostsFile, strings.TrimSpace(stderr.String()), err)
	}
	return nil
}

// addHostsEntry adds or replaces the /etc/hosts entry for a VM. A failure is
// reported to the caller but is non-fatal at the call site.
func addHostsEntry(name, ip, fqdn string) error {
	existing, err := os.ReadFile(hostsFile)
	if err != nil {
		return fmt.Errorf("reading %s: %w", hostsFile, err)
	}
	updated := upsertHostsBlock(string(existing), name, hostsBlock(name, ip, fqdn))
	if !strings.HasSuffix(updated, "\n") {
		updated += "\n"
	}
	return writeHostsFile(updated)
}

// removeHostsEntry removes the /etc/hosts entry for a VM.
func removeHostsEntry(name string) error {
	existing, err := os.ReadFile(hostsFile)
	if err != nil {
		return fmt.Errorf("reading %s: %w", hostsFile, err)
	}
	updated := strings.TrimRight(removeHostsBlock(string(existing), name), "\n") + "\n"
	return writeHostsFile(updated)
}

