func defaultCloudInit(cfg *config.Config) string {
	var b strings.Builder
	b.WriteString("#cloud-config\n")
	b.WriteString("users:\n")
	for i, u := range cfg.VM.Users {
		placeholder := "${SSH_PUBLIC_KEY}"
		if i > 0 {
