		b.WriteString("    sudo: ALL=(ALL) NOPASSWD:ALL\n")
		b.WriteString("    shell: /bin/bash\n")
		b.WriteString("    ssh_authorized_keys:\n")
		b.WriteString("      - " + placeholder + "\n")
	}
	return b.String()
}

