1	// Package libvirt implements the local VM provider backed by libvirt/KVM. All
2	// hypervisor interaction shells out to virsh, virt-install, and qemu-img via an
3	// explicit-argument Runner (no shell), so VM names and paths cannot inject
4	// commands.
5	package libvirt
6	
7	import (
8		"context"
9		"fmt"
10		"io"
11		"os"
12		"os/exec"
13		"path/filepath"
14		"strconv"
15		"strings"
16		"syscall"
17		"time"
18	
19		"github.com/gherlein/govirt/internal/cloudinit"
20		"github.com/gherlein/govirt/internal/config"
21		"github.com/gherlein/govirt/internal/provider"
22	)
23	
24	// DefaultPoolDir is the libvirt default storage pool directory.
25	const DefaultPoolDir = "/var/lib/libvirt/images"
26	
27	// DefaultNetwork is the libvirt network VMs attach to.
28	const DefaultNetwork = "default"
29	
30	// ImageEnsurer resolves an image shorthand to a local cached base image path.
31	// *images.Manager satisfies it.
32	type ImageEnsurer interface {
33		Ensure(ctx context.Context, image string) (string, error)
34	}
35	
36	// Provider is the libvirt VMProvider implementation.
37	type Provider struct {
38		Runner  Runner
39		Images  ImageEnsurer
40		PoolDir string
41		Verbose bool
42		Out     io.Writer
43	}
44	
45	// New returns a Provider with production defaults.
46	func New(images ImageEnsurer) *Provider {
47		return &Provider{
48			Runner:  execRunner{},
49			Images:  images,
50			PoolDir: DefaultPoolDir,
51			Out:     os.Stderr,
52		}
53	}
54	
55	// Name implements provider.VMProvider.
56	func (p *Provider) Name() string { return "local" }
57	
58	func (p *Provider) out() io.Writer {
59		if p.Out != nil {
60			return p.Out
61		}
62		return os.Stderr
63	}
64	
65	func (p *Provider) diskPath(name string) string {
66		return filepath.Join(p.PoolDir, name+".qcow2")
67	}
68	
69	func (p *Provider) isoPath(name string) string {
70		return filepath.Join(p.PoolDir, name+"-cloud-init.iso")
71	}
72	
73	// Create provisions a local VM from the processed cloud-init document at
74	// cloudInitPath.
75	func (p *Provider) Create(ctx context.Context, cfg *config.Config, cloudInitPath string) error {
76		if cfg.VM == nil {
77			return fmt.Errorf("config missing vm section")
78		}
79		name := cfg.VM.Name
80		if err := config.ValidateName(name); err != nil {
81			return err
82		}
83		if err := p.checkPrereqs(); err != nil {
84			return err
85		}
86		if p.exists(ctx, name) {
87			return fmt.Errorf("VM already exists: destroy first with 'govirt destroy %s'", name)
88		}
89	
90		base, err := p.Images.Ensure(ctx, cfg.VM.Image)
91		if err != nil {
92			return err
93		}
94	
95		disk := p.diskPath(name)
96		if err := p.createDisk(ctx, base, disk, cfg.VM.Disk); err != nil {
97			return err
98		}
99	
100		userData, err := os.ReadFile(cloudInitPath)
101		if err != nil {
102			return fmt.Errorf("reading processed cloud-init: %w", err)
103		}
104		iso := p.isoPath(name)
105		tool := detectISOTool()
106		if err := buildISO(ctx, p.Runner, tool, name, string(userData), iso); err != nil {
107			return err
108		}
109	
110		memMB, err := parseMemoryMB(cfg.VM.Memory)
111		if err != nil {
112			return err
113		}
114		variant := mapOSVariant(cfg.VM.Image)
115		args := buildVirtInstallArgs(name, memMB, cfg.VM.CPUs, disk, iso, variant, DefaultNetwork, cfg.VM.Mounts, true)
116		if err := p.Runner.Run(ctx, "virt-install", args...); err != nil {
117			return err
118		}
119	
120		ip := pollIP(ctx, p.Runner, name, DefaultNetwork, defaultIPPoll)
121		if ip == "" {
122			fmt.Fprintf(p.out(), "warning: VM started but no IP assigned after %s: check libvirt network with 'virsh net-list'\n", defaultIPPoll.timeout)
123		}
124	
125		cfg.Local = &config.LocalState{
126			IP:           ip,
127			DomainName:   name,
128			DiskPath:     disk,
129			CloudInitISO: iso,
130			Network:      DefaultNetwork,
131		}
132		return nil
133	}
134	
135	// createDisk builds a copy-on-write overlay over the cached base image and
136	// resizes it to the requested size.
137	func (p *Provider) createDisk(ctx context.Context, base, disk, size string) error {
138		if err := p.Runner.Run(ctx, "qemu-img", "create", "-f", "qcow2",
139			"-b", base, "-F", "qcow2", disk, size); err != nil {
140			return fmt.Errorf("creating VM disk: %w", err)
141		}
142		if err := p.Runner.Run(ctx, "qemu-img", "resize", disk, size); err != nil {
143			return fmt.Errorf("resizing VM disk: %w", err)
144		}
145		return nil
146	}
147	
148	// Delete force-stops and removes the VM, its storage, and the cloud-init ISO.
149	func (p *Provider) Delete(ctx context.Context, cfg *config.Config) error {
150		name := cfg.VM.Name
151		if err := config.ValidateName(name); err != nil {
152			return err
153		}
154		// Ignore error: the domain may already be stopped.
155		_ = p.Runner.Run(ctx, "virsh", "destroy", name)
156		if err := p.Runner.Run(ctx, "virsh", "undefine", name, "--remove-all-storage"); err != nil {
157			return err
158		}
159		if cfg.Local != nil && cfg.Local.CloudInitISO != "" {
160			os.Remove(cfg.Local.CloudInitISO)
161		} else {
162			os.Remove(p.isoPath(name))
163		}
164		cfg.Local = nil
165		return nil
166	}
167	
168	// Stop performs a graceful ACPI shutdown and waits for the domain to stop.
169	func (p *Provider) Stop(ctx context.Context, cfg *config.Config) error {
170		name := cfg.VM.Name
171		if err := config.ValidateName(name); err != nil {
172			return err
173		}
174		if err := p.Runner.Run(ctx, "virsh", "shutdown", name); err != nil {
175			return err
176		}
177		deadline := time.Now().Add(30 * time.Second)
178		for {
179			if p.domState(ctx, name) == "shut off" {
180				return nil
181			}
182			if time.Now().After(deadline) {
183				return fmt.Errorf("VM %s did not stop within 30s", name)
184			}
185			select {
186			case <-ctx.Done():
187				return ctx.Err()
188			case <-time.After(2 * time.Second):
189			}
190		}
191	}
192	
193	// Start boots the VM and refreshes its IP in state.
194	func (p *Provider) Start(ctx context.Context, cfg *config.Config) error {
195		name := cfg.VM.Name
196		if err := config.ValidateName(name); err != nil {
197			return err
198		}
199		if err := p.Runner.Run(ctx, "virsh", "start", name); err != nil {
200			return err
201		}
202		network := DefaultNetwork
203		if cfg.Local != nil && cfg.Local.Network != "" {
204			network = cfg.Local.Network
205		}
206		ip := pollIP(ctx, p.Runner, name, network, defaultIPPoll)
207		if ip != "" {
208			if cfg.Local == nil {
209				cfg.Local = &config.LocalState{Network: network, DomainName: name}
210			}
211			cfg.Local.IP = ip
212		}
213		return nil
214	}
215	
216	// Status reports the VM state and current IP.
217	func (p *Provider) Status(ctx context.Context, cfg *config.Config) (*provider.VMStatus, error) {
218		name := cfg.VM.Name
219		if err := config.ValidateName(name); err != nil {
220			return nil, err
221		}
222		state := p.domState(ctx, name)
223		if state == "" {
224			return nil, fmt.Errorf("VM not found: check 'govirt list' for available VMs")
225		}
226		network := DefaultNetwork
