// mapOSVariant maps an image shorthand to a libvirt os-variant. The second
// return reports whether the shorthand was recognized; unknown values fall back
// to ubuntu20.04 and known=false so the caller can warn.
func mapOSVariant(image string) (variant string, known bool) {
	switch image {
	case "24.04":
		return "ubuntu24.04", true
	case "22.04":
		return "ubuntu22.04", true
	case "20.04":
		return "ubuntu20.04", true
	default:
		return "ubuntu20.04", false
	}
}

// kernelRelease returns the running kernel release string, or "" if unreadable.
func kernelRelease() string {
	data, err := os.ReadFile("/proc/sys/kernel/osrelease")
	if err != nil {
		return ""
	}
	return strings.TrimSpace(string(data))
}

// kernelSupportsVirtiofs reports whether the kernel release is >= 5.4, the
// minimum for virtiofs. An unparseable release defaults to true (assume modern).
func kernelSupportsVirtiofs(release string) bool {
	if release == "" {
		return true
	}
	parts := strings.SplitN(release, ".", 3)
	if len(parts) < 2 {
		return true
	}
	major, err1 := strconv.Atoi(parts[0])
	minor, err2 := strconv.Atoi(parts[1])
	if err1 != nil || err2 != nil {
		return true
	}
	if major != 5 {
		return major > 5
	}
	return minor >= 4
}

