	if !isMAC("52:54:00:ab:cd:ef") {
		t.Error("valid MAC rejected")
	}
	for _, bad := range []string{"not-a-mac", "52:54:00", "default", "virtio"} {
		if isMAC(bad) {
			t.Errorf("%q accepted as MAC", bad)
		}
	}
}

