				fmt.Fprintf(os.Stderr, "warning: could not stream cloud-init log: %v\n", err)
			}
		}
	}
	return nil
}

// processCloudInit reads the stack cloud-init.yaml (or generates a default) and
// runs it through the processor.
func processCloudInit(ctx context.Context, cfg *config.Config, folder, name string, local bool) ([]byte, error) {
	ciPath := config.CloudInitPath(folder, name)
	var raw []byte
	if data, err := os.ReadFile(ciPath); err == nil {
		raw = data
	} else if os.IsNotExist(err) {
		raw = []byte(defaultCloudInit(cfg))
	} else {
		return nil, fmt.Errorf("reading %s: %w", ciPath, err)
	}
	return cloudinit.Process(ctx, cfg, raw, cloudinit.NewKeyFetcher(), local)
}

// updateLocalHosts adds an /etc/hosts entry for a freshly created local VM. A
// failure prints manual instructions and is non-fatal.
func updateLocalHosts(cfg *config.Config) {
	if cfg.Local == nil || cfg.Local.IP == "" {
		return
	}
	fqdn := ""
	if cfg.DNS != nil && cfg.DNS.Hostname != "" && cfg.DNS.Domain != "" {
		fqdn = cfg.DNS.Hostname + "." + cfg.DNS.Domain
	}
	if err := addHostsEntry(cfg.VM.Name, cfg.Local.IP, fqdn); err != nil {
		fmt.Fprintf(os.Stderr, "warning: could not update /etc/hosts: %v\n", err)
		fmt.Fprintf(os.Stderr, "add manually:\n%s\n", hostsBlock(cfg.VM.Name, cfg.Local.IP, fqdn))
		return
	}
	cfg.Local.HostsEntry = true
}

func cmdDestroy(ctx context.Context, args parsedArgs, folder string) error {
	cfg, cfgPath, err := loadStackConfig(args, folder)
	if err != nil {
		return err
	}
	providerName := selectProvider(args.provider, cfg)
	p, err := buildProvider(providerName, args.verbose)
	if err != nil {
		return err
	}
	hadHostsEntry := providerName == "local" && cfg.Local != nil && cfg.Local.HostsEntry
	if err := p.Delete(ctx, cfg); err != nil {
		return err
	}
	if hadHostsEntry {
		if err := removeHostsEntry(args.name); err != nil {
			fmt.Fprintf(os.Stderr, "warning: could not remove /etc/hosts entry: %v\n", err)
		}
	}
	if err := config.Save(cfgPath, cfg); err != nil {
		return err
	}
	fmt.Printf("destroyed %s (%s)\n", args.name, providerName)
	return nil
}

func cmdList(ctx context.Context, args parsedArgs) error {
	providerName := args.provider
	if providerName == "" {
		providerName = "local"
	}
	p, err := buildProvider(providerName, args.verbose)
	if err != nil {
		return err
	}
	vms, err := p.List(ctx)
	if err != nil {
		return err
	}
	w := tabwriter.NewWriter(os.Stdout, 0, 0, 2, ' ', 0)
	fmt.Fprintln(w, "NAME\tSTATE\tIP\tPROVIDER")
	for _, vm := range vms {
		fmt.Fprintf(w, "%s\t%s\t%s\t%s\n", vm.Name, vm.State, vm.IP, vm.Provider)
	}
	return w.Flush()
}

func cmdStatus(ctx context.Context, args parsedArgs, folder string) error {
	cfg, _, err := loadStackConfig(args, folder)
	if err != nil {
		return err
	}
	providerName := selectProvider(args.provider, cfg)
	p, err := buildProvider(providerName, args.verbose)
	if err != nil {
		return err
	}
	st, err := p.Status(ctx, cfg)
	if err != nil {
		return err
	}
	fmt.Printf("name:     %s\nstate:    %s\nprovider: %s\nip:       %s\n", st.Name, st.State, st.Provider, st.IP)
	return nil
}

// cmdSimple handles ssh, stop, and start which load the stack and dispatch to a
// single provider method.
func cmdSimple(ctx context.Context, args parsedArgs, folder, op string) error {
	cfg, cfgPath, err := loadStackConfig(args, folder)
	if err != nil {
		return err
	}
	providerName := selectProvider(args.provider, cfg)
	p, err := buildProvider(providerName, args.verbose)
	if err != nil {
		return err
	}
	switch op {
	case "ssh":
		return p.SSH(ctx, cfg)
	case "stop":
		if err := p.Stop(ctx, cfg); err != nil {
			return err
		}
	case "start":
		if err := p.Start(ctx, cfg); err != nil {
			return err
		}
	}
	if err := config.Save(cfgPath, cfg); err != nil {
		return err
	}
	fmt.Printf("%s %s (%s)\n", op, args.name, providerName)
	return nil
}

func cmdDNS(ctx context.Context, args parsedArgs, folder string) error {
	if args.subcommand != "swap" {
		return fmt.Errorf("usage: govirt dns swap <name>")
	}
	cfg, cfgPath, err := loadStackConfig(args, folder)
	if err != nil {
		return err
	}
	providerName := selectProvider(args.provider, cfg)
	if providerName == "local" {
		return fmt.Errorf("dns swap is not available for local VMs")
	}
	p, err := buildProvider(providerName, args.verbose)
	if err != nil {
		return err
	}
	swapper, ok := p.(provider.DNSSwapper)
	if !ok {
		return fmt.Errorf("provider %q does not support dns swap", providerName)
	}
	if err := swapper.SwapDNS(ctx, cfg); err != nil {
		return err
	}
	if err := config.Save(cfgPath, cfg); err != nil {
		return err
	}
	fmt.Printf("swapped DNS for %s (%s)\n", args.name, providerName)
	return nil
}

func printUsage() {
	fmt.Print(`govirt - provision VMs locally or in the cloud

Usage:
  govirt create <name> [--aws|--do|--local]   Create a VM
  govirt destroy <name>                        Destroy a VM (auto-detects provider)
  govirt list [--aws|--do]                     List VMs
  govirt ssh <name>                            SSH into a VM
  govirt status <name>                         Show VM status
  govirt stop <name>                           Gracefully stop a VM
  govirt start <name>                          Start a VM
  govirt dns swap <name>                       Point DNS at the current VM IP (cloud only)

Flags:
  --aws                  Use AWS provider
  --do, --digitalocean   Use DigitalOcean provider
  --local                Use local libvirt provider
  --dir PATH             Config directory (stacks at <dir>/stacks)
  --folder, -f PATH      Stacks folder (overrides --dir)
  --users, -u USERS      GitHub usernames for SSH key injection (comma-separated)
  --no-hosts             Skip /etc/hosts management for local VMs
  --verbose, -v          Verbose output
  --version              Show version
  --help, -h             Show this help

Config dir: ` + filepath.Join(homeDir(), ".config", "govirt", "stacks") + "\n")
}

